// Build Gmail search query from WRM webhook params
// Input: { dateFrom, dateTo, senderContains, subjectContains, limit }
const body = $input.first().json.body || $input.first().json;

const dateFrom = body.dateFrom;
const dateTo   = body.dateTo;
const sender   = (body.senderContains  || '').trim();
const subject  = (body.subjectContains || '').trim();
const limit    = Math.min(parseInt(body.limit, 10) || 10, 10);

function toGmailDate(iso) {
  const d = new Date(iso);
  return `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
}

// Gmail 'before' is exclusive — bump +1 day to include the full dateTo day
const exclusiveTo = new Date(dateTo);
exclusiveTo.setUTCDate(exclusiveTo.getUTCDate() + 1);

const parts = [
  `after:${toGmailDate(dateFrom)}`,
  `before:${toGmailDate(exclusiveTo.toISOString())}`,
];
if (sender)  parts.push(`from:${sender}`);
if (subject) parts.push(`subject:${subject}`);

return [{ json: { searchQuery: parts.join(' '), limit } }];

// Normalize Gmail output to match Outlook/Graph API shape
// so WRM's callWebhook() handles both identically.
return $input.all().map(item => {
  const m = item.json;

  // Parse 'Name <email@domain.com>' or plain 'email@domain.com'
  const fromStr = m.from || '';
  const match = fromStr.match(/^(.+?)\s*<([^>]+)>\s*$/);
  const fromName    = match ? match[1].trim() : fromStr;
  const fromAddress = match ? match[2].trim() : fromStr;

  // Prefer textPlain; fall back to textHtml
  const bodyContent = m.textPlain || m.textHtml || '';

  return {
    json: {
      // Prefix 'gmail:' to namespace Gmail IDs away from Outlook IDs
      internetMessageId: `gmail:${m.id}`,
      subject:           m.subject           || null,
      receivedDateTime:  m.date              || null,
      hasAttachments:    Array.isArray(m.attachments) && m.attachments.length > 0,
      body: {
        contentType: m.textPlain ? 'text' : 'html',
        content:     bodyContent,
      },
      from: {
        emailAddress: {
          name:    fromName || fromAddress,
          address: fromAddress,
        },
      },
    },
  };
});
